real_t s172(struct args_t * func_args)
{
    struct{int a;int b;} * x = func_args->arg_info;
    int n1 = x->a;
    int n3 = x->b;

    initialise_arrays(__func__);
    gettimeofday(&func_args->t1, NULL);

    real_t * __restrict__ a_ = a;
    real_t * __restrict__ b_ = b;

    for (int nl = 0; nl < iterations; nl++) {
        int start = n1 - 1;
        int stride = n3;

        if (stride == 1) {
            #pragma clang loop vectorize(enable)
            for (int i = start; i < LEN_1D; ++i) {
                a_[i] += b_[i];
            }
        } else if (stride == 2) {
            #pragma clang loop vectorize(enable)
            for (int i = start; i < LEN_1D; i += 2) {
                a_[i] += b_[i];
            }
        } else if (stride == 4) {
            #pragma clang loop vectorize(enable)
            for (int i = start; i < LEN_1D; i += 4) {
                a_[i] += b_[i];
            }
        } else {
            // General fallback: use pointer arithmetic and explicit trip count
            // to help the compiler vectorize variable stride loops
            if (stride > 0) {
                int limit = LEN_1D;
                int offset = start;
                // Calculate the number of iterations
                int trip_count = (limit - offset + stride - 1) / stride;
                if (trip_count > 0) {
                    real_t * __restrict__ pa = a_ + offset;
                    real_t * __restrict__ pb = b_ + offset;
                    #pragma clang loop vectorize(enable)
                    for (int k = 0; k < trip_count; ++k) {
                        pa[k * stride] += pb[k * stride];
                    }
                }
            } else {
                // Handle non-positive stride (though unlikely in this benchmark)
                for (int i = start; i < LEN_1D; i += stride) {
                    a_[i] += b_[i];
                }
            }
        }
        dummy(a, b, c, d, e, aa, bb, cc, 0.);
    }

    gettimeofday(&func_args->t2, NULL);
    return calc_checksum(__func__);
}

real_t s1113(struct args_t * func_args)
{
    initialise_arrays(__func__);
    gettimeofday(&func_args->t1, NULL);

    for (int nl = 0; nl < 2*iterations; nl++) {
        int mid = LEN_1D / 2;
        int i;

        real_t * __restrict__ a_ = a;
        real_t * __restrict__ b_ = b;

        // Phase 1: i < mid
        // a[i] uses the original value of a[mid] before it is overwritten
        #pragma clang loop vectorize(enable) interleave(enable)
        for (i = 0; i < mid; i++) {
            a_[i] = a_[mid] + b_[i];
        }

        // Phase 2: i == mid
        // a[mid] is updated here. Subsequent reads must see this new value.
        a_[mid] = a_[mid] + b_[mid];

        // Phase 3: i > mid
        // a[i] uses the updated value of a[mid]
        #pragma clang loop vectorize(enable) interleave(enable)
        for (i = mid + 1; i < LEN_1D; i++) {
            a_[i] = a_[mid] + b_[i];
        }

        dummy(a, b, c, d, e, aa, bb, cc, 0.);
    }

    gettimeofday(&func_args->t2, NULL);
    return calc_checksum(__func__);
}

real_t s122(struct args_t * func_args)
{

//    induction variable recognition
//    variable lower and upper bound, and stride
//    reverse data access and jump in data access

    struct{int a;int b;} * x = func_args->arg_info;
    int n1 = x->a;
    int n3 = x->b;

    initialise_arrays(__func__);
    gettimeofday(&func_args->t1, NULL);

    real_t * __restrict__ a_ptr = a;
    real_t * __restrict__ b_ptr = b;

    int j, k;
    for (int nl = 0; nl < iterations; nl++) {
        j = 1;
        k = 0;

        int start = n1 - 1;
        int stride = n3;

        if (stride == 1) {
            // Fast path for stride == 1: Direct vectorization
            // k = i - start + 1 (since k starts at 0, i starts at start)
            // a[i] += b[LEN_1D - k]
            // a[i] += b[LEN_1D - (i - start + 1)]
            // a[i] += b[LEN_1D - i + start - 1]
            #pragma clang loop vectorize(enable)
            for (int i = start; i < LEN_1D; i++) {
                a_ptr[i] += b_ptr[LEN_1D - (i - start) - 1];
            }
        } else {
            // Generic path for stride > 1: Two-phase precomputation
            int k_vals[LEN_1D];
            int idx = 0;

            // Phase 1: Precompute induction variable k
            for (int i = start; i < LEN_1D; i += stride) {
                k += j;
                k_vals[idx++] = k;
            }

            // Phase 2: Vectorized data access
            #pragma clang loop vectorize(enable)
            for (int t = 0; t < idx; t++) {
                int i = start + t * stride;
                a_ptr[i] += b_ptr[LEN_1D - k_vals[t]];
            }
        }

        dummy(a, b, c, d, e, aa, bb, cc, 0.);
    }

    gettimeofday(&func_args->t2, NULL);
    return calc_checksum(__func__);
}
